const https = require('https');
const { URL } = require('url');

const token = process.env.GHL_PRIVATE_INTEGRATION_TOKEN_TJB;
if (!token) {
  console.error('Missing env GHL_PRIVATE_INTEGRATION_TOKEN_TJB');
  process.exit(2);
}

const base = 'https://services.leadconnectorhq.com';
const locationId = 'TW8JsPW5NMnA3tfK2XLn';
const targetStage = '691672ae-ed9c-41c5-b708-39689acf3faf';
const nowMs = Date.parse('2026-03-19T18:58:00Z');
const cutoffMs = 24 * 60 * 60 * 1000;

function req(method, path, body) {
  return new Promise((resolve, reject) => {
    const url = new URL(path, base);
    const data = body ? Buffer.from(JSON.stringify(body)) : null;
    const opts = {
      method,
      hostname: url.hostname,
      path: url.pathname + url.search,
      headers: {
        Authorization: `Bearer ${token}`,
        Version: '2021-07-28',
        Accept: 'application/json'
      }
    };
    if (data) {
      opts.headers['Content-Type'] = 'application/json';
      opts.headers['Content-Length'] = data.length;
    }

    const r = https.request(opts, (res) => {
      let chunks = '';
      res.on('data', (d) => (chunks += d));
      res.on('end', () => {
        let parsed;
        try {
          parsed = chunks ? JSON.parse(chunks) : null;
        } catch {
          parsed = { raw: chunks };
        }
        if (res.statusCode >= 200 && res.statusCode < 300) {
          resolve({ status: res.statusCode, data: parsed });
        } else {
          reject(new Error(`${method} ${path} => ${res.statusCode} ${chunks.slice(0, 500)}`));
        }
      });
    });
    r.on('error', reject);
    if (data) r.write(data);
    r.end();
  });
}

const norm = (s) =>
  (s || '')
    .toString()
    .toLowerCase()
    .replace(/[\u2018\u2019\u201c\u201d]/g, "'")
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();

function tasksFromPayload(p) {
  if (!p) return [];
  if (Array.isArray(p)) return p;
  if (Array.isArray(p.tasks)) return p.tasks;
  if (p.data) {
    if (Array.isArray(p.data)) return p.data;
    if (Array.isArray(p.data.tasks)) return p.data.tasks;
  }
  return [];
}

async function run() {
  const all = [];
  let nextPath = `/opportunities/search?location_id=${encodeURIComponent(locationId)}&limit=100`;
  let guard = 0;

  while (nextPath && guard < 50) {
    guard += 1;
    const r = await req('GET', nextPath);
    const d = r.data || {};
    const arr = Array.isArray(d.opportunities)
      ? d.opportunities
      : Array.isArray(d.data?.opportunities)
      ? d.data.opportunities
      : Array.isArray(d.data)
      ? d.data
      : Array.isArray(d.items)
      ? d.items
      : [];

    all.push(...arr);

    const nextPageUrl = d.meta?.nextPageUrl;
    if (nextPageUrl) {
      const u = new URL(nextPageUrl);
      nextPath = u.pathname + u.search;
    } else {
      nextPath = '';
    }
  }

  const stale = all.filter((o) => {
    const stage = o.pipelineStageId || o.stageId || o.stage || o.pipelineStage?.id;
    if (stage !== targetStage) return false;
    const t = o.lastStageChangeAt || o.dateUpdated || o.updatedAt || o.lastStatusChangeAt;
    const ms = t ? Date.parse(t) : NaN;
    if (!Number.isFinite(ms)) return false;
    return nowMs - ms >= cutoffMs;
  });

  let tagged = 0;
  let tagErrors = 0;
  let tasksCreated = 0;
  let tasksExistingOpen = 0;
  let taskErrors = 0;
  const contactNames = [];

  const followupBase =
    'Please complete manual 24-hour follow-up for this new lead in Agentic AI Suite Pipeline. Review conversation history, attempt outreach, and update opportunity notes/stage.';

  for (const o of stale) {
    const contactId = o.contactId || o.contact?.id;
    if (!contactId) {
      taskErrors += 1;
      continue;
    }

    const name =
      o.contactName || o.contact?.name || [o.firstName, o.lastName].filter(Boolean).join(' ') || contactId;
    contactNames.push(name);

    try {
      await req('POST', `/contacts/${encodeURIComponent(contactId)}/tags`, {
        tags: ['needs-followup-24h', 'manual-task-required']
      });
      tagged += 1;
    } catch {
      tagErrors += 1;
    }

    const oppName = o.name || o.opportunityTitle || 'Opportunity';
    const followupText = `${followupBase} Opportunity: ${oppName}. Opportunity ID: ${o.id || 'unknown'}.`;
    const title = `TJB 24h New Lead Follow-up - ${name}`;

    let existing = [];
    try {
      const tr = await req(
        'GET',
        `/contacts/${encodeURIComponent(contactId)}/tasks?locationId=${encodeURIComponent(
          locationId
        )}&limit=100`
      );
      existing = tasksFromPayload(tr.data);
    } catch {
      taskErrors += 1;
      continue;
    }

    const titlePrefixNorm = norm('TJB 24h New Lead Follow-up');
    const bodyNorm = norm(followupText);

    const match = existing.find((t) => {
      const tt = norm(t.title || t.name || '');
      const tb = norm(t.body || t.description || t.notes || '');
      const completed = t.completed === true;
      const status = norm(t.status || '');
      const isOpen = !(completed || ['completed', 'done', 'closed'].includes(status));
      if (!isOpen) return false;
      if (tt.startsWith(titlePrefixNorm)) return true;
      if (tb.includes(bodyNorm)) return true;
      return false;
    });

    if (match) {
      tasksExistingOpen += 1;
      continue;
    }

    const dueDate = new Date(nowMs + cutoffMs).toISOString();
    try {
      await req('POST', `/contacts/${encodeURIComponent(contactId)}/tasks`, {
        title,
        body: followupText,
        dueDate,
        completed: false
      });
      tasksCreated += 1;
    } catch {
      taskErrors += 1;
    }
  }

  const result = {
    checked: all.length,
    staleCount: stale.length,
    tagged,
    tagErrors,
    tasksCreated,
    tasksExistingOpen,
    taskErrors,
    contacts: [...new Set(contactNames)]
  };

  console.log(JSON.stringify(result, null, 2));
}

run().catch((e) => {
  console.error(e?.stack || String(e));
  process.exit(1);
});

